/**
 * LightningSnowflake Effect
 * Combina raios elétricos com estrelas de refrigeração (snowflakes)
 *
 * USO:
 *   const canvas = document.getElementById('meu-canvas');
 *   const effect = new LightningSnowflake(canvas, { speed: 1 });
 *
 *   // Mudar velocidade em tempo real:
 *   effect.setSpeed(2);
 *
 *   // Parar o efeito:
 *   effect.dispose();
 *
 * OPÇÕES:
 *   speed      - velocidade geral (0.5 = lento, 1 = normal, 2 = rápido, 3 = frenético)
 *   mainColor  - cor principal dos raios (default: "#FFFFFF")
 *   coreColor  - cor do núcleo dos raios (default: "#A8E4FF")
 *   branchColor- cor dos galhos dos raios (default: "#0A74FF")
 *   glowColor  - cor do glow (default: "#4FC3FF")
 */
(function () {
  function LightningSnowflake(canvas, options = {}) {
    const ctx = canvas.getContext('2d');
    let W, H, CX, CY, raf, t = 0;

    const config = {
      mainColor: "#FFFFFF",
      coreColor: "#A8E4FF",
      branchColor: "#0A74FF",
      glowColor: "#4FC3FF",
      speed: 1,
      ...options
    };

    const S = () => config.speed;
    const COLORS = [config.mainColor, config.coreColor, config.branchColor, config.glowColor, '#7dd6ff'];
    const ICE_COLORS = ['#A8E4FF', '#7dd6ff', '#b3f0ff', '#FFFFFF'];

    const bolts = [], particles = [], explosions = [], snowflakes = [], iceFragments = [];
    let cT = 0, eT = 0, bT = 0, aT = 0, sT = 0;

    // ---------- helpers ----------
    function rand(a, b) { return a + Math.random() * (b - a); }
    function pick(arr) { return arr[Math.floor(Math.random() * arr.length)]; }

    function resize() {
      W = canvas.clientWidth;
      H = canvas.clientHeight;
      canvas.width = W;
      canvas.height = H;
      CX = W / 2;
      CY = H / 2;
    }

    function zigzag(x1, y1, x2, y2, segs, noise) {
      const pts = [];
      const dx = x2 - x1, dy = y2 - y1;
      const len = Math.sqrt(dx * dx + dy * dy) || 1;
      const px = -dy / len, py = dx / len;
      for (let i = 0; i <= segs; i++) {
        const tt = i / segs;
        const bx = x1 + dx * tt, by = y1 + dy * tt;
        const env = Math.sin(tt * Math.PI) * noise * (1 + Math.random() * 0.5);
        pts.push({ x: bx + px * env * (Math.random() - 0.5) * 2, y: by + py * env * (Math.random() - 0.5) * 2 });
      }
      return pts;
    }

    function strokePts(pts, col, lw, blur) {
      if (pts.length < 2) return;
      ctx.beginPath(); ctx.moveTo(pts[0].x, pts[0].y);
      for (let i = 1; i < pts.length; i++) ctx.lineTo(pts[i].x, pts[i].y);
      ctx.shadowBlur = blur; ctx.shadowColor = col; ctx.strokeStyle = col;
      ctx.lineWidth = lw; ctx.lineCap = 'round'; ctx.stroke();
    }

    // ---------- Snowflake ----------
    class Snowflake {
      constructor(x, y, opts = {}) {
        this.x = x; this.y = y;
        this.targetR = opts.r ?? rand(40, 90);
        this.r = 0;
        this.life = 1;
        this.decay = (opts.decay ?? rand(0.004, 0.01)) * S();
        this.arms = 6;
        this.branches = Math.floor(rand(2, 4));
        this.rotation = Math.random() * Math.PI;
        this.rotSpeed = (Math.random() - 0.5) * 0.01 * S();
        this.col = opts.col ?? pick([...ICE_COLORS, config.glowColor]);
        this.sparkle = Math.random() < 0.5;
        this.scale = 0;
      }
      update() {
        this.life -= this.decay;
        this.rotation += this.rotSpeed * S();
        if (this.scale < 1) this.scale = Math.min(1, this.scale + 0.04 * S());
        this.r = this.targetR * this.scale;
      }
      draw() {
        const a = Math.max(0, this.life);
        ctx.globalAlpha = a;
        ctx.save();
        ctx.translate(this.x, this.y);
        ctx.rotate(this.rotation);

        for (let arm = 0; arm < this.arms; arm++) {
          ctx.save();
          ctx.rotate((arm / this.arms) * Math.PI * 2);

          // tronco principal
          ctx.beginPath(); ctx.moveTo(0, 0); ctx.lineTo(0, -this.r);
          ctx.shadowBlur = 12; ctx.shadowColor = this.col;
          ctx.strokeStyle = this.col; ctx.lineWidth = 1.5; ctx.stroke();

          // ramos secundários
          for (let b = 1; b <= this.branches; b++) {
            const by = -this.r * (b / (this.branches + 1));
            const bl = this.r * 0.28 * (1 - b * 0.12);
            [-1, 1].forEach(dir => {
              ctx.beginPath(); ctx.moveTo(0, by);
              ctx.lineTo(dir * bl, by - bl * 0.6);
              ctx.shadowBlur = 8; ctx.shadowColor = this.col;
              ctx.strokeStyle = this.col; ctx.lineWidth = 1; ctx.stroke();

              // sub-ramos
              if (bl > 8) {
                ctx.beginPath();
                ctx.moveTo(dir * bl * 0.5, by - bl * 0.3);
                ctx.lineTo(dir * (bl * 0.5 + bl * 0.22), by - bl * 0.3 - bl * 0.22 * 0.55);
                ctx.lineWidth = 0.6; ctx.stroke();
              }
            });
          }

          // ponta
          ctx.beginPath(); ctx.arc(0, -this.r, 2.2, 0, Math.PI * 2);
          ctx.fillStyle = this.col; ctx.shadowBlur = 10; ctx.shadowColor = this.col; ctx.fill();

          ctx.restore();
        }

        // núcleo central
        const gr = ctx.createRadialGradient(0, 0, 0, 0, 0, this.r * 0.18);
        gr.addColorStop(0, `rgba(168,228,255,${a})`);
        gr.addColorStop(0.5, `rgba(79,195,255,${a * 0.7})`);
        gr.addColorStop(1, 'rgba(79,195,255,0)');
        ctx.fillStyle = gr;
        ctx.beginPath(); ctx.arc(0, 0, this.r * 0.18, 0, Math.PI * 2); ctx.fill();

        // brilho
        if (this.sparkle && Math.random() < 0.3 * S()) {
          ctx.beginPath(); ctx.arc(0, 0, this.r * 0.08, 0, Math.PI * 2);
          ctx.fillStyle = `rgba(255,255,255,${a * 0.9})`;
          ctx.shadowBlur = 20; ctx.shadowColor = '#fff'; ctx.fill();
        }

        ctx.restore();
        ctx.globalAlpha = 1;
      }
    }

    // ---------- Bolt ----------
    class Bolt {
      constructor(x1, y1, x2, y2, opts = {}) {
        this.x1 = x1; this.y1 = y1; this.x2 = x2; this.y2 = y2;
        this.life = 1;
        this.decay = (opts.decay ?? rand(0.04, 0.12)) * S();
        this.segs = opts.segs ?? Math.floor(rand(8, 18));
        this.noise = opts.noise ?? rand(15, 45);
        this.color = opts.color ?? pick(COLORS);
        this.width = opts.width ?? rand(1, 3);
        this.flicker = Math.random() < 0.4;
        this.pts = zigzag(x1, y1, x2, y2, this.segs, this.noise);
        this.branches = this._makeBranches();
      }
      _makeBranches() {
        const br = [], count = Math.floor(rand(1, 5));
        for (let i = 0; i < count; i++) {
          const idx = Math.floor(rand(2, this.pts.length - 2));
          if (!this.pts[idx]) continue;
          const p = this.pts[idx];
          const ang = Math.atan2(this.y2 - this.y1, this.x2 - this.x1) + (Math.random() - 0.5) * 2.5;
          const len = rand(20, 70);
          const bpts = zigzag(p.x, p.y, p.x + Math.cos(ang) * len, p.y + Math.sin(ang) * len, 6, this.noise * 0.4);
          br.push({ pts: bpts, w: this.width * 0.5 });
          if (Math.random() < 0.3) {
            const last = bpts[bpts.length - 1];
            const ang2 = ang + (Math.random() - 0.5) * 2;
            const l2 = rand(10, 30);
            br.push({ pts: zigzag(last.x, last.y, last.x + Math.cos(ang2) * l2, last.y + Math.sin(ang2) * l2, 4, 5), w: this.width * 0.3 });
          }
        }
        return br;
      }
      update() {
        this.life -= this.decay;
        if (this.life < 0.4 && Math.random() < 0.3)
          this.pts = zigzag(this.x1, this.y1, this.x2, this.y2, this.segs, this.noise * this.life);
      }
      draw() {
        if (this.flicker && Math.random() < 0.3) return;
        const a = Math.max(0, this.life);
        ctx.globalAlpha = a;
        strokePts(this.pts, this.color, this.width, 16);
        strokePts(this.pts, '#ffffff', this.width * 0.3, 0);
        for (const b of this.branches) strokePts(b.pts, config.branchColor, b.w, 8);
        ctx.globalAlpha = 1;
      }
    }

    // ---------- Particle ----------
    class Particle {
      constructor(x, y, cold = false) {
        const ang = Math.random() * Math.PI * 2;
        const spd = rand(1, 5) * S();
        this.x = x; this.y = y;
        this.vx = Math.cos(ang) * spd; this.vy = Math.sin(ang) * spd;
        this.life = 1; this.decay = rand(0.015, 0.04) * S();
        this.tail = rand(8, 20); this.w = rand(0.5, 1.5);
        this.col = cold ? pick(ICE_COLORS) : pick(COLORS);
        this.dot = Math.random() < 0.35;
        this.cold = cold;
      }
      update() {
        this.x += this.vx; this.y += this.vy;
        this.vy += 0.03 * S(); this.vx *= 0.99; this.vy *= 0.99;
        this.life -= this.decay;
      }
      draw() {
        const a = Math.max(0, this.life);
        ctx.globalAlpha = a;
        if (this.dot) {
          ctx.beginPath(); ctx.arc(this.x, this.y, this.w * 2 * a, 0, Math.PI * 2);
          ctx.fillStyle = this.col; ctx.fill();
          if (this.cold) {
            ctx.beginPath(); ctx.arc(this.x, this.y, this.w * 4 * a, 0, Math.PI * 2);
            ctx.strokeStyle = this.col; ctx.lineWidth = 0.5; ctx.stroke();
          }
        } else {
          const tx = this.x - this.vx * this.tail, ty = this.y - this.vy * this.tail;
          const pts = zigzag(tx, ty, this.x, this.y, 5, 3 * a);
          strokePts(pts, this.col, this.w, 8);
          strokePts(pts, '#ffffff', this.w * 0.3, 0);
        }
        ctx.globalAlpha = 1;
      }
    }

    // ---------- CenterExplosion ----------
    class CenterExplosion {
      constructor(x, y, icy = false) {
        this.x = x; this.y = y; this.life = 1;
        this.decay = 0.014 * S(); this.icy = icy;
        this.rays = [];
        const count = Math.floor(rand(icy ? 6 : 8, icy ? 12 : 16));
        for (let i = 0; i < count; i++) {
          const ang = icy ? (i / count) * Math.PI * 2 : Math.random() * Math.PI * 2;
          const len = rand(40, 130);
          this.rays.push({
            pts: zigzag(x, y, x + Math.cos(ang) * len, y + Math.sin(ang) * len, 8, icy ? 8 : 15),
            w: rand(0.8, 2.5),
            col: icy ? pick(ICE_COLORS) : pick(COLORS)
          });
        }
      }
      update() { this.life -= this.decay; }
      draw() {
        const a = Math.max(0, this.life);
        ctx.globalAlpha = a;
        const r = 8 + (1 - a) * 60;
        const g = ctx.createRadialGradient(this.x, this.y, 0, this.x, this.y, r);
        const cc = this.icy ? '79,195,255' : '255,255,255';
        g.addColorStop(0, `rgba(${cc},${a})`);
        g.addColorStop(0.4, `rgba(79,195,255,${a * 0.6})`);
        g.addColorStop(1, 'transparent');
        ctx.fillStyle = g; ctx.beginPath();
        ctx.arc(this.x, this.y, r, 0, Math.PI * 2); ctx.fill();
        for (const ray of this.rays) {
          strokePts(ray.pts, ray.col, ray.w, 14);
          strokePts(ray.pts, '#ffffff', ray.w * 0.3, 0);
        }
        ctx.globalAlpha = 1;
      }
    }

    // ---------- IceFragment ----------
    class IceFragment {
      constructor(x, y) {
        const ang = Math.random() * Math.PI * 2;
        const spd = rand(0.8, 2) * S();
        this.x = x; this.y = y;
        this.vx = Math.cos(ang) * spd; this.vy = Math.sin(ang) * spd;
        this.life = 1; this.decay = rand(0.01, 0.025) * S();
        this.size = rand(4, 12);
        this.rot = Math.random() * Math.PI;
        this.rotv = (Math.random() - 0.5) * 0.08 * S();
        this.col = pick(ICE_COLORS);
      }
      update() {
        this.x += this.vx; this.y += this.vy;
        this.vy += 0.015 * S(); this.rot += this.rotv;
        this.life -= this.decay;
      }
      draw() {
        const a = Math.max(0, this.life);
        ctx.globalAlpha = a * 0.8;
        ctx.save(); ctx.translate(this.x, this.y); ctx.rotate(this.rot);
        const n = 6, r = this.size;
        ctx.beginPath();
        for (let i = 0; i < n; i++) {
          const angle = (i / n) * Math.PI * 2;
          const outer = i % 2 === 0 ? r : r * 0.5;
          const x2 = Math.cos(angle) * outer, y2 = Math.sin(angle) * outer;
          i === 0 ? ctx.moveTo(x2, y2) : ctx.lineTo(x2, y2);
        }
        ctx.closePath();
        ctx.strokeStyle = this.col; ctx.lineWidth = 0.8;
        ctx.shadowBlur = 6; ctx.shadowColor = this.col; ctx.stroke();
        ctx.restore();
        ctx.globalAlpha = 1;
      }
    }

    // ---------- spawn helpers ----------
    function spawnCornerBolt() {
      const corners = [{ x: 0, y: 0 }, { x: W, y: 0 }, { x: 0, y: H }, { x: W, y: H }];
      const c = pick(corners);
      bolts.push(new Bolt(c.x, c.y, CX + rand(-80, 80), CY + rand(-80, 80)));
    }
    function spawnEdgeBolt() {
      const edge = Math.floor(Math.random() * 4);
      let x1, y1;
      if (edge === 0) { x1 = rand(0, W); y1 = 0; }
      else if (edge === 1) { x1 = rand(0, W); y1 = H; }
      else if (edge === 2) { x1 = 0; y1 = rand(0, H); }
      else { x1 = W; y1 = rand(0, H); }
      const ang = Math.atan2(CY - y1, CX - x1) + (Math.random() - 0.5) * 1.2;
      const dist = rand(80, Math.min(W, H) * 0.7);
      bolts.push(new Bolt(x1, y1, x1 + Math.cos(ang) * dist, y1 + Math.sin(ang) * dist));
    }
    function spawnAmbient() {
      const x = rand(50, W - 50), y = rand(50, H - 50);
      const ang = Math.random() * Math.PI * 2, len = rand(30, 90);
      bolts.push(new Bolt(x, y, x + Math.cos(ang) * len, y + Math.sin(ang) * len, { decay: rand(0.06, 0.16) * S(), noise: rand(10, 25) }));
    }
    function spawnExplosion() {
      const icy = Math.random() < 0.4;
      const ex = CX + rand(-50, 50), ey = CY + rand(-50, 50);
      explosions.push(new CenterExplosion(ex, ey, icy));
      for (let i = 0; i < 30; i++) particles.push(new Particle(ex, ey, icy));
      if (icy) {
        for (let i = 0; i < 12; i++) iceFragments.push(new IceFragment(ex, ey));
        snowflakes.push(new Snowflake(ex, ey, { r: rand(35, 65), decay: rand(0.006, 0.012) * S() }));
      }
    }
    function spawnSnowflake() {
      const x = rand(80, W - 80), y = rand(80, H - 80);
      snowflakes.push(new Snowflake(x, y, { r: rand(20, 55), decay: rand(0.004, 0.01) * S() }));
    }
    function spawnSnowflakeBolt(sf) {
      const ang = Math.random() * Math.PI * 2;
      const tx = sf.x + Math.cos(ang) * rand(60, 150);
      const ty = sf.y + Math.sin(ang) * rand(60, 150);
      bolts.push(new Bolt(sf.x, sf.y, tx, ty, { color: pick(ICE_COLORS), noise: rand(8, 20), decay: rand(0.06, 0.1) * S() }));
    }

    // ---------- loop principal ----------
    function loop() {
      if (!canvas.isConnected) { if (raf) cancelAnimationFrame(raf); return; }

      ctx.fillStyle = 'rgba(0,0,0,0.13)';
      ctx.fillRect(0, 0, W, H);
      ctx.shadowBlur = 0;

      t += 0.016 * S();
      cT += 0.016 * S(); eT += 0.016 * S();
      bT += 0.016 * S(); aT += 0.016 * S(); sT += 0.016 * S();

      if (cT > rand(0.4, 1.0) / S()) { spawnCornerBolt(); cT = 0; }
      if (bT > rand(0.15, 0.45) / S()) { spawnEdgeBolt(); if (Math.random() < 0.4) spawnEdgeBolt(); bT = 0; }
      if (eT > rand(1.5, 3.0) / S()) { spawnExplosion(); eT = 0; }
      if (aT > rand(0.1, 0.3) / S()) { spawnAmbient(); if (Math.random() < 0.3) spawnAmbient(); aT = 0; }
      if (sT > rand(0.8, 2.0) / S()) { spawnSnowflake(); sT = 0; }

      // brilho central suave azulado
      const gr = ctx.createRadialGradient(CX, CY, 0, CX, CY, Math.min(W, H) * 0.35);
      gr.addColorStop(0, 'rgba(10,116,255,0.05)');
      gr.addColorStop(0.5, 'rgba(79,195,255,0.02)');
      gr.addColorStop(1, 'transparent');
      ctx.fillStyle = gr; ctx.fillRect(0, 0, W, H);

      // snowflakes (atrás)
      for (let i = snowflakes.length - 1; i >= 0; i--) {
        snowflakes[i].update(); snowflakes[i].draw();
        if (snowflakes[i].life > 0.3 && Math.random() < 0.02 * S()) spawnSnowflakeBolt(snowflakes[i]);
        if (snowflakes[i].life <= 0) snowflakes.splice(i, 1);
      }
      for (let i = iceFragments.length - 1; i >= 0; i--) {
        iceFragments[i].update(); iceFragments[i].draw();
        if (iceFragments[i].life <= 0) iceFragments.splice(i, 1);
      }
      for (let i = bolts.length - 1; i >= 0; i--) {
        bolts[i].update(); bolts[i].draw();
        if (bolts[i].life <= 0) bolts.splice(i, 1);
      }
      for (let i = explosions.length - 1; i >= 0; i--) {
        explosions[i].update(); explosions[i].draw();
        if (explosions[i].life <= 0) explosions.splice(i, 1);
      }
      for (let i = particles.length - 1; i >= 0; i--) {
        particles[i].update(); particles[i].draw();
        if (particles[i].life <= 0) particles.splice(i, 1);
      }

      ctx.shadowBlur = 0;
      raf = requestAnimationFrame(loop);
    }

    function init() {
      resize();
      window.addEventListener('resize', resize);
      // seed inicial
      for (let i = 0; i < 4; i++) spawnCornerBolt();
      for (let i = 0; i < 6; i++) spawnEdgeBolt();
      for (let i = 0; i < 8; i++) spawnAmbient();
      for (let i = 0; i < 3; i++) spawnSnowflake();
      loop();
    }

    init();

    return {
      dispose: () => {
        if (raf) cancelAnimationFrame(raf);
        window.removeEventListener('resize', resize);
      },
      setSpeed: (v) => { config.speed = Math.max(0.1, v); }
    };
  }

  window.LightningSnowflake = LightningSnowflake;

  // Mantém compatibilidade com o nome anterior
  window.TubesCursor = LightningSnowflake;
})();